import java.io.FileWriter;
import java.io.IOException;
import org.apache.commons.text.StringEscapeUtils;

public class XssSecureCode {
    public static void main(String[] args) throws IOException {
        String userInput = "<script>alert('XSS Attack!')</script>";
        String sanitizedInput = StringEscapeUtils.escapeHtml4(userInput);

        FileWriter fileWriter = new FileWriter("output.html");
        fileWriter.write("<html>");
        fileWriter.write("<head><title>XSS Secure</title></head>");
        fileWriter.write("<body>");
        fileWriter.write("<p>User Input: " + sanitizedInput + "</p>");
        fileWriter.write("</body>");
        fileWriter.write("</html>");

        fileWriter.close();
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
